command:
mkdir -p pr-corpus && printf '{"pattern_id":"p1","resolved":false,"existing_rule_id":"r-x"}
' > pr-corpus/decisions.jsonl && printf '[{"id":"p1","verbatim_quote":"x","usefulness_estimate":4,"supporting_prs":[{"number":1,"org":"a","tier":1},{"number":2,"org":"b","tier":1},{"number":3,"org":"c","tier":1}]}]
' > pr-corpus/patterns.json && printf '{"gate":"pass"}
' > pr-corpus/quality-eval.json && bash "$CLAUDE_PLUGIN_ROOT/commands/pr-corpus-learn.sh" --patterns pr-corpus/patterns.json --gate-result pr-corpus/quality-eval.json --decisions-log pr-corpus/decisions.jsonl 2>err.txt; rc=$?; [ "$rc" -ne 0 ] && grep -q 'promotion_blocked' err.txt && grep -q 'unresolved_conflict' err.txt && echo blocked 1>&2
